import React, { useState, useEffect } from 'react';
import './CompetitionsPage.css';

const competitionsData = {
  '2022': {
    panitia: '/competitions/2022/panitia.jpg',
    events: [
      {
        id: 'drone',
        title: 'Drone',
        bg: '/competitions/2022/drone.jpg',
        desc: 'Kompetisi drone racing dan misi otomatis yang menguji kemampuan navigasi dan kontrol UAV secara presisi.',
      },
      {
        id: 'wf',
        title: 'WF',
        bg: '/competitions/2022/wf.jpg',
        desc: 'Workshop Festival — ajang unjuk kreativitas dan inovasi teknologi oleh tim asisten laboratorium.',
      },
      {
        id: 'rcv',
        title: 'Robot Computer Vision',
        bg: '/competitions/2022/rcv.jpg',
        desc: 'Robot berbasis computer vision yang mampu mendeteksi, mengklasifikasi, dan merespons objek secara real-time.',
      },
    ],
  },
  '2025': {
    panitia: '/competitions/2025/panitia.jpg',
    events: [
      {
        id: 'drone',
        title: 'Drone',
        bg: '/competitions/2025/drone.jpg',
        desc: 'Kompetisi drone racing dan misi otomatis yang menguji kemampuan navigasi dan kontrol UAV secara presisi.',
      },
      {
        id: 'wf',
        title: 'WF',
        bg: '/competitions/2025/wf.jpg',
        desc: 'Workshop Festival — ajang unjuk kreativitas dan inovasi teknologi oleh tim asisten laboratorium.',
      },
      {
        id: 'gripper',
        title: 'Robot Gripper',
        bg: '/competitions/2025/gripper.jpg',
        desc: 'Robot gripper otomatis yang dirancang untuk memindahkan dan menyortir objek dengan akurasi tinggi.',
      },
      {
        id: 'psk',
        title: 'Proyek Sistem Komputer',
        bg: '/competitions/2025/psk.jpg',
        desc: 'Kompetisi perancangan sistem komputer terintegrasi mulai dari hardware hingga software aplikasi.',
      },
    ],
  },
  '2026': {
    panitia: '/competitions/2026/panitia.jpg',
    events: [
      {
        id: 'drone',
        title: 'Drone',
        bg: '/competitions/2026/drone.jpg',
        desc: 'Kompetisi drone racing dan misi otomatis yang menguji kemampuan navigasi dan kontrol UAV secara presisi.',
      },
      {
        id: 'wf',
        title: 'WF',
        bg: '/competitions/2026/wf.jpg',
        desc: 'Workshop Festival — ajang unjuk kreativitas dan inovasi teknologi oleh tim asisten laboratorium.',
      },
      {
        id: 'triathlon',
        title: 'Triathlon Robot',
        bg: '/competitions/2026/triathlon.jpg',
        desc: 'Robot serba bisa yang harus melewati tiga tantangan berbeda: navigasi, manipulasi objek, dan komunikasi nirkabel.',
      },
      {
        id: 'psk',
        title: 'Proyek Sistem Komputer',
        bg: '/competitions/2026/psk.jpg',
        desc: 'Kompetisi perancangan sistem komputer terintegrasi mulai dari hardware hingga software aplikasi.',
      },
    ],
  },
};

const years = ['2022', '2025', '2026'];

export default function CompetitionsPage() {
  const [activeYear, setActiveYear] = useState('2026');
  const [slideIndex, setSlideIndex] = useState(0);
  const isCurrentYear = activeYear === '2026';

  // AUTO SLIDE
  useEffect(() => {
    const interval = setInterval(() => {
      setSlideIndex((prev) =>
        prev === data.panitia.length - 1 ? 0 : prev + 1
      );
    }, 3000); // 3 detik

    return () => clearInterval(interval);
  }, [data.panitia.length]);


  return (
    <>
      <section className="page-header">
        <div className="container">
          <h1>ESC Competition</h1>
          <p>Ajang kompetisi teknologi tahunan dari Pusat Studi Multimedia dan Robotika UG</p>
        </div>
      </section>

      <section className="competitions-section">
        <div className="container">

          {/* Year Tabs */}
          <div className="year-tabs">
            {years.map(year => (
              <button
                key={year}
                className={`year-tab ${activeYear === year ? 'active' : ''}`}
                onClick={() => setActiveYear(year)}
              >
                {year}
                {year === '2026' && <span className="year-badge-live">Live</span>}
              </button>
            ))}
          </div>

          {/* Panitia Photo */}
          <div className="panitia-section">
            <div className="panitia-label">
              <span>📸 Foto Panitia ESC {activeYear}</span>
            </div>
            <div className="panitia-img-wrap">
              <img src={data.panitia} alt={`Panitia ESC ${activeYear}`} />
              <div className="panitia-overlay">
                <h3>ESC {activeYear}</h3>
                <p>Electronic Student Competition — Pusat Studi Multimedia & Robotika UG</p>
              </div>
            </div>
          </div>

          <div className="panitia-slider">
            {data.panitia.map((img, index) => (
              <div
                key={index}
                className={`panitia-slide ${
                  index === slideIndex ? 'active' : ''
                }`}
              >
                <img src={img} alt={`Panitia ${index}`} />
              </div>
            ))}

            {/* DOTS */}
            <div className="panitia-dots">
              {data.panitia.map((_, i) => (
                <span
                  key={i}
                  className={i === slideIndex ? 'active' : ''}
                  onClick={() => setSlideIndex(i)}
                />
              ))}
            </div>
          </div>

          {/* Event Cards */}
          <div className="events-section">
            <h2 className="events-title">Cabang Lomba</h2>
            <div className="events-grid">
              {data.events.map((event, i) => (
                <div
                  key={event.id}
                  className="event-card"
                  style={{ '--bg': `url(${event.bg})` }}
                >
                  <div className="event-card-bg" />
                  <div className="event-card-content">
                    <div className="event-card-top">
                      <span className="event-number">{String(i + 1).padStart(2, '0')}</span>
                    </div>
                    <div className="event-card-bottom">
                      <h3>{event.title}</h3>
                      <p>{event.desc}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Daftar Button */}
          <div className="daftar-competition-section">
            <div className="daftar-competition-box">
              <div className="daftar-competition-text">
                <h2>
                  {isCurrentYear
                    ? 'Daftarkan Tim Kamu!'
                    : `ESC ${activeYear} Telah Selesai`}
                </h2>
                <p>
                  {isCurrentYear
                    ? 'Pendaftaran ESC 2026 masih dibuka. Segera daftarkan tim kamu sebelum kuota penuh!'
                    : `Kompetisi ESC ${activeYear} telah berakhir. Terima kasih kepada seluruh peserta yang telah berpartisipasi.`}
                </p>
              </div>
              <button
                className={`btn-daftar-competition ${!isCurrentYear ? 'disabled' : ''}`}
                disabled={!isCurrentYear}
              >
                {isCurrentYear ? 'Daftar Sekarang' : 'Pendaftaran Ditutup'}
              </button>
            </div>
          </div>

        </div>
      </section>
    </>
  );
}
